import React from "react";

function Navbar() {
  return (
    <nav className="navbar">
      <h2>🌴 Paradise Resort</h2>
      <ul>
        <li>Home</li>
        <li>About</li>
        <li>Gallery</li>
        <li>Contact</li>
      </ul>
    </nav>
  );
}

export default Navbar;
